#include<bits/stdc++.h>
using namespace std;
const long long mod=998244353;
long long fastpow(long long x,long long y)
{
    long long ans=1;
    while(y)
    {
        if(y&1)
        {
            ans=ans*x%mod;
        }
        x=x*x%mod;
        y>>=1;
    }
    return ans;
}
struct matrix
{
    int a[2][2];
    matrix(int x=0)
    {
        memset(a,0,sizeof(a));
        if(x==1)
        {
            a[0][0]=a[1][1]=1;
        }
    }
    void clear()
    {
        (*this)=matrix();
    }
    void init()
    {
        a[0][0]=a[1][1]=1;
    }
    friend matrix operator*(const matrix&a,const matrix&b)
    {
        matrix c;
        c.a[0][0]=(1ll*a.a[0][0]*b.a[0][0]+1ll*a.a[0][1]*b.a[1][0])%mod;
        c.a[0][1]=(1ll*a.a[0][0]*b.a[0][1]+1ll*a.a[0][1]*b.a[1][1])%mod;
        c.a[1][0]=(1ll*a.a[1][0]*b.a[0][0]+1ll*a.a[1][1]*b.a[1][0])%mod;
        c.a[1][1]=(1ll*a.a[1][0]*b.a[0][1]+1ll*a.a[1][1]*b.a[1][1])%mod;
        return c;
    }
    friend void operator*=(matrix &a,const matrix &b)
    {
        a=a*b;
    }
    friend bool operator==(const matrix&a,const matrix&b)
    {
        for(int i=0;i<2;i++)
        {
            for(int j=0;j<2;j++)
            {
                if(a.a[i][j]!=b.a[i][j])
                {
                    return false;
                }
            }
        }
        return true;
    }
