struct segment_tree
{
    struct node
    {
        int l,r;
        int lson,rson;
        matrix sum;
    }a[1500010];
    long long cnt;
    segment_tree():cnt(0){}
    void pushup(long long x)
    {
        a[x].sum=(a[a[x].lson].sum*a[a[x].rson].sum);
    }
    long long init(matrix b[],long long l,long long r)
    {
        long long x=++cnt,mid=(l+r)>>1;
        a[x].l=l;
        a[x].r=r;
        if(l==r)
        {
            a[x].sum=b[l];
            return x;
        }
        a[x].lson=init(b,l,mid);
        a[x].rson=init(b,mid+1,r);
        pushup(x);
        return x;
    }
    void update(long long x,long long p,matrix z)
    {
        if(a[x].l>p||a[x].r<p)
        {
            return;
        }
        if(a[x].l==a[x].r)
        {
            a[x].sum=z;
            return;
        }
        update(a[x].lson,p,z);
        update(a[x].rson,p,z);
        pushup(x);
    }
    matrix query(long long x,long long l,long long r)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return matrix(1);
        }
        if(a[x].l>=l&&a[x].r<=r)
        {
            return a[x].sum;
        }
        return (query(a[x].lson,l,r)*query(a[x].rson,l,r));
    }
}t1,t2;
int a[500010],b[500010];
int mpa[500010],mpb[500010];
int main()
{
    srand(time(0));
    int n,m;
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
        while(mpa[a[i]]==0)
        {
            mpa[a[i]]=1ll*rand()*rand()%mod;
        }
        while(mpb[a[i]]==0)
        {
            mpb[a[i]]=1ll*rand()*rand()%mod;
        }
        long long va=mpa[a[i]],vb=mpb[a[i]];
        vals[i].a[0][0]=va;
        vals[i].a[0][1]=(((1-va*va%mod)%mod+mod)%mod)*fastpow(vb,mod-2)%mod;
        vals[i].a[1][0]=vb;
        vals[i].a[1][1]=mod-va;
    }
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&b[i]);
        while(mpa[b[i]]==0)
        {
            mpa[b[i]]=1ll*rand()*rand()%mod;
        }
        while(mpb[b[i]]==0)
        {
            mpb[b[i]]=1ll*rand()*rand()%mod;
        }
        long long va=mpa[b[i]],vb=mpb[b[i]];
        valt[i].a[0][0]=va;
        valt[i].a[0][1]=(((1-va*va%mod)%mod+mod)%mod)*fastpow(vb,mod-2)%mod;
        valt[i].a[1][0]=vb;
        valt[i].a[1][1]=mod-va;
    }
    t1.init(vals,1,n);
    t2.init(valt,1,n);
    while(m--)
    {
        int op;
        scanf("%d",&op);
        if(op==1)
        {
            int l1,r1,l2,r2;
            scanf("%d%d%d%d",&l1,&r1,&l2,&r2);
            if(t1.query(1,l1,r1)==t2.query(1,l2,r2))
            {
                printf("Yes\n");
            }
            else
            {
                printf("No\n");
            }
        }
        else if(op==2)
        {
            int x,y;
            scanf("%d%d",&x,&y);
            a[x]=y;
            while(mpa[a[x]]==0)
            {
                mpa[a[x]]=1ll*rand()*rand()%mod;
            }
            while(mpb[a[x]]==0)
            {
                mpb[a[x]]=1ll*rand()*rand()%mod;
            }
            long long va=mpa[a[x]],vb=mpb[a[x]];
            vals[x].a[0][0]=va;
            vals[x].a[0][1]=(((1-va*va%mod)%mod+mod)%mod)*fastpow(vb,mod-2)%mod;
            vals[x].a[1][0]=vb;
            vals[x].a[1][1]=mod-va;
            t1.update(1,x,vals[x]);
        }
        else
        {
            int x,y;
            scanf("%d%d",&x,&y);
            b[x]=y;
            while(mpa[b[x]]==0)
            {
                mpa[b[x]]=1ll*rand()*rand()%mod;
            }
            while(mpb[b[x]]==0)
            {
                mpb[b[x]]=1ll*rand()*rand()%mod;
            }
            long long va=mpa[b[x]],vb=mpb[b[x]];
            valt[x].a[0][0]=va;
            valt[x].a[0][1]=(((1-va*va%mod)%mod+mod)%mod)*fastpow(vb,mod-2)%mod;
            valt[x].a[1][0]=vb;
            valt[x].a[1][1]=mod-va;
            t2.update(1,x,valt[x]);
        }
    }
    return 0;
}
